	RetryCooldown             []string `json:"retry_cooldown,omitempty"`
	ExternalBlocked           []string `json:"external_blocked,omitempty"`
	NotEligible               []string `json:"not_eligible,omitempty"`
	Superseded                []string `json:"superseded,omitempty"`
